    69  func tokenRevoked(c *contextmodel.ReqContext, err *auth.TokenRevokedError) {
    70          if c.IsApiRequest() {
    71                  c.JSON(http.StatusUnauthorized, map[string]any{
    72                          "message": "Token revoked",
    73                          "error": map[string]any{
    74                                  "id":                    "ERR_TOKEN_REVOKED",
    75                                  "maxConcurrentSessions": err.MaxConcurrentSessions,
    76                          },
    77                  })
    78                  return
    79          }
    80
    81          if !c.UseSessionStorageRedirect {
    82                  writeRedirectCookie(c)
    83                  c.Redirect(setting.AppSubUrl + "/login")
    84                  return
    85          }
    86
    87          c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
    88  }
