   228                                          builder.WriteString("(dashboard.folder_id IN (SELECT d.id FROM dashboard as d ")
   229                                          recQueryName := fmt.Sprintf("RecQry%d", len(f.recQueries))
   230                                          f.addRecQry(recQueryName, permSelector.String(), permSelectorArgs, orgID)
   231                                          builder.WriteString(fmt.Sprintf("WHERE d.org_id = ? AND d.uid IN (SELECT uid FROM %s)", recQueryName))
   232                                          args = append(args, orgID)
   233                                  default:
   234                                          nestedFoldersSelectors, nestedFoldersArgs := f.nestedFoldersSelectors(permSelector.String(), permSelectorArgs, "dashboard", "folder_id", "d.id", orgID)
   235                                          builder.WriteRune('(')
   236                                          builder.WriteString(nestedFoldersSelectors)
   237                                          args = append(args, nestedFoldersArgs...)
   238                                  }
   239                          } else {
   240                                  builder.WriteString("(dashboard.folder_id IN (SELECT d.id FROM dashboard as d ")
   241                                  builder.WriteString("WHERE 1 = 0")
   242                          }
   243                          builder.WriteString(") AND NOT dashboard.is_folder)")
   244
   245                          // Include all the dashboards under the root if the user has the required permissions on the root (used to be the General folder)
   246                          if hasAccessToRoot(f.dashboardAction, f.user) {
   247                                  builder.WriteString(" OR (dashboard.folder_id = 0 AND NOT dashboard.is_folder)")
   248                          }
   249                  } else {
   250                          builder.WriteString("NOT dashboard.is_folder")
   251                  }
   252          }
   253
   254          // recycle and reuse
   255          permSelector.Reset()
   256          permSelectorArgs = permSelectorArgs[:0]
   257
   258          if f.folderAction != "" {
   259                  if f.dashboardAction != "" {
   260                          builder.WriteString(" OR ")
   261                  }
   262
   263                  toCheck := actionsToCheck(f.folderAction, f.folderActionSets, f.user.GetPermissions(), folderWildcards)
   264
   265                  if len(toCheck) > 0 {
   266                          if !useSelfContainedPermissions {
   267                                  permSelector.WriteString("(SELECT identifier FROM permission WHERE kind = 'folders' AND attribute = 'uid'")
   268                                  permSelector.WriteString(rolesFilter)
   269                                  permSelectorArgs = append(permSelectorArgs, params...)
   270                                  if len(toCheck) == 1 {
   271                                          permSelector.WriteString(" AND action = ?")
   272                                          permSelectorArgs = append(permSelectorArgs, toCheck[0])
   273                                  } else {
   274                                          permSelector.WriteString(" AND action IN (?" + strings.Repeat(", ?", len(toCheck)-1) + ")")
   275                                          permSelectorArgs = append(permSelectorArgs, toCheck...)
   276                                  }
   277                          } else {
   278                                  permSelectorArgs = getAllowedUIDs(f.folderAction, f.user, dashboards.ScopeFoldersPrefix)
   279
   280                                  if len(permSelectorArgs) > 0 {
   281                                          permSelector.WriteString("(?" + strings.Repeat(", ?", len(permSelectorArgs)-1) + "")
   282                                  } else {
   283                                          permSelector.WriteString("(")
   284                                  }
   285                          }
   286
   287                          permSelector.WriteRune(')')
   288
   289                          if len(permSelectorArgs) > 0 {
   290                                  switch f.recursiveQueriesAreSupported {
   291                                  case true:
   292                                          recQueryName := fmt.Sprintf("RecQry%d", len(f.recQueries))
   293                                          f.addRecQry(recQueryName, permSelector.String(), permSelectorArgs, orgID)
   294                                          builder.WriteString("(dashboard.uid IN ")
   295                                          builder.WriteString(fmt.Sprintf("(SELECT uid FROM %s)", recQueryName))
   296                                  default:
   297                                          nestedFoldersSelectors, nestedFoldersArgs := f.nestedFoldersSelectors(permSelector.String(), permSelectorArgs, "dashboard", "uid", "d.uid", orgID)
   298                                          builder.WriteRune('(')
   299                                          builder.WriteString(nestedFoldersSelectors)
   300                                          builder.WriteRune(')')
   301                                          args = append(args, nestedFoldersArgs...)
   302                                  }
   303                          } else {
   304                                  builder.WriteString("(1 = 0")
   305                          }
   306                          builder.WriteString(" AND dashboard.is_folder)")
   307                  } else {
   308                          builder.WriteString("dashboard.is_folder")
   309                  }
   310          }
   311
   312          builder.WriteRune(')')
   313
   314          f.where = clause{string: builder.String(), params: args}
   315  }
