   317  // With returns:
   318  // - a with clause for fetching folders with inherited permissions if nested folders are enabled or an empty string
   319  func (f *accessControlDashboardPermissionFilter) With() (string, []any) {
   320          var sb bytes.Buffer
   321          var params []any
   322          if len(f.recQueries) > 0 {
   323                  sb.WriteString("WITH RECURSIVE ")
   324                  sb.WriteString(f.recQueries[0].string)
   325                  params = append(params, f.recQueries[0].params...)
   326                  for _, r := range f.recQueries[1:] {
   327                          sb.WriteRune(',')
   328                          sb.WriteString(r.string)
   329                          params = append(params, r.params...)
   330                  }
   331          }
   332          return sb.String(), params
   333  }
