   335  func (f *accessControlDashboardPermissionFilter) addRecQry(queryName string, whereUIDSelect string, whereParams []any, orgID int64) {
   336          forceIndex := ""
   337          if f.dialect.DriverName() == migrator.MySQL {
   338                  forceIndex = " FORCE INDEX (IDX_folder_org_id_parent_uid) "
   339          }
   340
   341          if f.recQueries == nil {
   342                  f.recQueries = make([]clause, 0, maximumRecursiveQueries)
   343          }
   344          c := make([]any, len(whereParams))
   345          copy(c, whereParams)
   346          c = append([]any{orgID}, c...)
   347          f.recQueries = append(f.recQueries, clause{
   348                  // covered by UQE_folder_org_id_uid and UQE_folder_org_id_parent_uid_title
   349                  string: fmt.Sprintf(`%s AS (
   350                          SELECT uid, parent_uid, org_id FROM folder WHERE org_id = ? AND uid IN %s
   351                          UNION ALL SELECT f.uid, f.parent_uid, f.org_id FROM folder f %s INNER JOIN %s r ON f.parent_uid = r.uid and f.org_id = r.org_id
   352                  )`, queryName, whereUIDSelect, forceIndex, queryName),
   353                  params: c,
   354          })
   355  }
