   357  func actionsToCheck(action string, actionSets []string, permissions map[string][]string, wildcards ...accesscontrol.Wildcards) []any {
   358          for _, scope := range permissions[action] {
   359                  for _, w := range wildcards {
   360                          if w.Contains(scope) {
   361                                  return []any{}
   362                          }
   363                  }
   364          }
   365
   366          toCheck := []any{action}
   367          for _, a := range actionSets {
   368                  toCheck = append(toCheck, a)
   369          }
   370
   371          return toCheck
   372  }
