   374  func (f *accessControlDashboardPermissionFilter) nestedFoldersSelectors(permSelector string, permSelectorArgs []any, leftTable string, leftCol string, rightTableCol string, orgID int64) (string, []any) {
   375          wheres := make([]string, 0, folder.MaxNestedFolderDepth+1)
   376          args := make([]any, 0, len(permSelectorArgs)*(folder.MaxNestedFolderDepth+1))
   377
   378          joins := make([]string, 0, folder.MaxNestedFolderDepth+2)
   379
   380          // covered by UQE_folder_org_id_uid
   381          tmpl := "INNER JOIN folder %s ON %s.%s = %s.uid AND %s.org_id = %s.org_id "
   382
   383          prev := "d"
   384          onCol := "uid"
   385          for i := 1; i <= folder.MaxNestedFolderDepth+2; i++ {
   386                  t := fmt.Sprintf("f%d", i)
   387                  s := fmt.Sprintf(tmpl, t, prev, onCol, t, prev, t)
   388                  joins = append(joins, s)
   389
   390                  // covered by UQE_folder_org_id_uid
   391                  wheres = append(wheres, fmt.Sprintf("(%s.org_id = ? AND %s.%s IN (SELECT %s FROM dashboard d %s WHERE %s.org_id = ? AND %s.uid IN %s)", leftTable, leftTable, leftCol, rightTableCol, strings.Join(joins, " "), t, t, permSelector))
   392                  args = append(args, orgID, orgID)
   393                  args = append(args, permSelectorArgs...)
   394
   395                  prev = t
   396                  onCol = "parent_uid"
   397          }
   398
   399          return strings.Join(wheres, ") OR "), args
   400  }
