   402  func getAllowedUIDs(action string, user identity.Requester, scopePrefix string) []any {
   403          uidScopes := user.GetPermissions()[action]
   404
   405          args := make([]any, 0, len(uidScopes))
   406          for _, uidScope := range uidScopes {
   407                  if !strings.HasPrefix(uidScope, scopePrefix) {
   408                          continue
   409                  }
   410                  uid := strings.TrimPrefix(uidScope, scopePrefix)
   411                  args = append(args, uid)
   412          }
   413
   414          return args
   415  }
