   417  // Checks if the user has the required permissions on the root (used to be the General folder)
   418  func hasAccessToRoot(actionToCheck string, user identity.Requester) bool {
   419          generalFolderScope := dashboards.ScopeFoldersProvider.GetResourceScopeUID(folder.GeneralFolderUID)
   420          return slices.Contains(user.GetPermissions()[actionToCheck], generalFolderScope)
   421  }

