   101  func (m dashboardPermissionsMigrator) migratePermissions(dashes []dashboard, aclMap map[int64][]dashboards.DashboardACL, migrator *migrator.Migrator) error {
   102          permissionMap := map[int64]map[string][]*ac.Permission{}
   103          for _, d := range dashes {
   104                  if d.ID == -1 {
   105                          continue
   106                  }
   107                  acls := aclMap[d.ID]
   108                  if permissionMap[d.OrgID] == nil {
   109                          permissionMap[d.OrgID] = map[string][]*ac.Permission{}
   110                  }
   111
   112                  if (d.IsFolder || d.FolderID == 0) && len(acls) == 0 && !d.HasAcl {
   113                          permissionMap[d.OrgID]["managed:builtins:editor:permissions"] = append(
   114                                  permissionMap[d.OrgID]["managed:builtins:editor:permissions"],
   115                                  m.mapPermission(d.ID, dashboardaccess.PERMISSION_EDIT, d.IsFolder)...,
   116                          )
   117                          permissionMap[d.OrgID]["managed:builtins:viewer:permissions"] = append(
   118                                  permissionMap[d.OrgID]["managed:builtins:viewer:permissions"],
   119                                  m.mapPermission(d.ID, dashboardaccess.PERMISSION_VIEW, d.IsFolder)...,
   120                          )
   121                  } else {
   122                          for _, a := range deduplicateAcl(acls) {
   123                                  roleName := getRoleName(a)
   124                                  permissionMap[d.OrgID][roleName] = append(
   125                                          permissionMap[d.OrgID][roleName],
   126                                          m.mapPermission(d.ID, a.Permission, d.IsFolder)...,
   127                                  )
   128                          }
   129                  }
   130          }
   131
   132          var allRoles []*ac.Role
   133          rolesToCreate := []*ac.Role{}
   134          for orgID, roles := range permissionMap {
   135                  for name := range roles {
   136                          role, err := m.findRole(orgID, name)
   137                          if err != nil {
   138                                  return fmt.Errorf("failed to find role %s: %w", name, err)
   139                          }
   140                          if role.ID == 0 {
   141                                  rolesToCreate = append(rolesToCreate, &ac.Role{OrgID: orgID, Name: name})
   142                          } else {
   143                                  allRoles = append(allRoles, &role)
   144                          }
   145                  }
   146          }
   147
   148          migrator.Logger.Debug(fmt.Sprintf("bulk-creating roles %v", rolesToCreate))
   149          createdRoles, err := m.bulkCreateRoles(rolesToCreate)
   150          if err != nil {
   151                  return fmt.Errorf("failed to bulk-create roles: %w", err)
   152          }
   153
   154          allRoles = append(allRoles, createdRoles...)
   155
   156          if err := m.bulkAssignRoles(createdRoles); err != nil {
   157                  return fmt.Errorf("failed to bulk-assign roles: %w", err)
   158          }
   159
   160          return m.setPermissions(allRoles, permissionMap, migrator)
   161  }
