   163  func (m dashboardPermissionsMigrator) setPermissions(allRoles []*ac.Role, permissionMap map[int64]map[string][]*ac.Permission, migrator *migrator.Migrator) error {
   164          now := time.Now()
   165          for _, role := range allRoles {
   166                  migrator.Logger.Debug(fmt.Sprintf("setting permissions for role %s with ID %d in org %d", role.Name, role.ID, role.OrgID))
   167                  if _, err := m.sess.Exec("DELETE FROM permission WHERE role_id = ? AND (action LIKE ? OR action LIKE ?)", role.ID, "dashboards%", "folders%"); err != nil {
   168                          return fmt.Errorf("failed to clear dashboard and folder permissions for role: %w", err)
   169                  }
   170                  var permissions []ac.Permission
   171                  mappedPermissions := permissionMap[role.OrgID][role.Name]
   172                  for _, p := range mappedPermissions {
   173                          permissions = append(permissions, ac.Permission{
   174                                  RoleID:  role.ID,
   175                                  Action:  p.Action,
   176                                  Scope:   p.Scope,
   177                                  Updated: now,
   178                                  Created: now,
   179                          })
   180                  }
   181
   182                  err := batch(len(permissions), batchSize, func(start, end int) error {
   183                          migrator.Logger.Debug(fmt.Sprintf("inserting permissions %v", permissions[start:end]))
   184                          if _, err := m.sess.InsertMulti(permissions[start:end]); err != nil {
   185                                  return fmt.Errorf("failed to create permissions for role: %w", err)
   186                          }
   187                          return nil
   188                  })
   189                  if err != nil {
   190                          return err
   191                  }
   192          }
   193          return nil
   194  }
