   226  func deduplicateAcl(acl []dashboards.DashboardACL) []dashboards.DashboardACL {
   227          output := make([]dashboards.DashboardACL, 0, len(acl))
   228          uniqueACL := map[string]dashboards.DashboardACL{}
   229          for _, item := range acl {
   230                  // acl items with userID or teamID is enforced to be unique by sql constraint, so we can skip those
   231                  if item.UserID > 0 || item.TeamID > 0 {
   232                          output = append(output, item)
   233                          continue
   234                  }
   235
   236                  // better to make sure so we don't panic
   237                  if item.Role == nil {
   238                          continue
   239                  }
   240
   241                  current, ok := uniqueACL[string(*item.Role)]
   242                  if !ok {
   243                          uniqueACL[string(*item.Role)] = item
   244                          continue
   245                  }
   246
   247                  if current.Permission < item.Permission {
   248                          uniqueACL[string(*item.Role)] = item
   249                  }
   250          }
   251
   252          for _, item := range uniqueACL {
   253                  output = append(output, item)
   254          }
   255
   256          return output
   257  }
