   813          query := `SELECT r.uid, p.action, p.scope FROM role r
   814  LEFT OUTER JOIN permission p ON p.role_id = r.id
   815  WHERE r.uid IN (?, ?, ?) AND p.action LIKE 'annotations:%' AND p.scope IN ('*', 'annotations:*', 'annotations:type:*', 'annotations:type:dashboard')
