    10
    11  // Mapping maps a verb to a RBAC action and a resource name to a RBAC scope.
    12  type Mapping interface {
    13          // action returns the action for the given verb.
    14          // If no action is found, it returns false.
    15          Action(verb string) (string, bool)
    16          // ActionSets returns the action sets for the given verb.
    17          // If no action sets are found, it returns an empty slice. This is expected for resources that do not have action sets (anything apart from dashboards and folders).
    18          ActionSets(verb string) []string
    19          // scope returns the scope for the given resource name.
    20          Scope(name string) string
    21          // prefix returns the scope prefix for the translation.
    22          Prefix() string
    23          // AllActions returns all the actions for the translation.
    24          AllActions() []string
    25          // HasFolderSupport returns true if the translation supports folders.
    26          HasFolderSupport() bool
    27          // SkipScopeOnCreate returns true if the translation does not require a scope on create.
    28          SkipScopeOnCreate() bool
    29  }
    30
    31  type translation struct {
    32          resource          string
    33          attribute         string
    34          verbMapping       map[string]string
    35          actionSetMapping  map[string][]string
    36          folderSupport     bool
    37          skipScopeOnCreate bool
    38          // use this option if you need to limit access to users that can access all resources
    39          useWildcardScope bool
    40  }
    41
    42  func (t translation) Action(verb string) (string, bool) {
    43          action, ok := t.verbMapping[verb]
    44          return action, ok
    45  }
    46
    47  func (t translation) ActionSets(verb string) []string {
    48          actionSets := t.actionSetMapping[verb]
    49          return actionSets
    50  }
    51
    52  func (t translation) Scope(name string) string {
    53          if t.useWildcardScope {
    54                  return "*"
    55          }
    56          return t.resource + ":" + t.attribute + ":" + name
    57  }
    58
    59  func (t translation) Prefix() string {
    60          return t.resource + ":" + t.attribute + ":"
    61  }
    62
    63  func (t translation) AllActions() []string {
    64          actions := make([]string, 0, len(t.verbMapping))
    65          actionsMap := make(map[string]bool)
    66          for _, action := range t.verbMapping {
    67                  if actionsMap[action] {
    68                          continue
    69                  }
    70                  actionsMap[action] = true
    71                  actions = append(actions, action)
    72          }
    73          return actions
    74  }
    75
    76  func (t translation) HasFolderSupport() bool {
    77          return t.folderSupport
    78  }
    79
    80  func (t translation) SkipScopeOnCreate() bool {
    81          return t.skipScopeOnCreate
    82  }
    83
    84  // MapperRegistry is a registry of mappers that maps a group and resource to a translation.
    85  type MapperRegistry interface {
    86          // Get returns the permission mapper for the given group and resource.
    87          // If no translation is found, it returns false.
    88          Get(group, resource string) (Mapping, bool)
    89          // GetAll returns all the translations for the given group
    90          GetAll(group string) []Mapping
    91  }
    92
    93  type mapper map[string]map[string]translation
    94
    95  func newResourceTranslation(resource string, attribute string, folderSupport, skipScopeOnCreate bool) translation {
    96          defaultMapping := func(r string) map[string]string {
    97                  return map[string]string{
    98                          utils.VerbGet:              fmt.Sprintf("%s:read", r),
    99                          utils.VerbList:             fmt.Sprintf("%s:read", r),
   100                          utils.VerbWatch:            fmt.Sprintf("%s:read", r),
   101                          utils.VerbCreate:           fmt.Sprintf("%s:create", r),
   102                          utils.VerbUpdate:           fmt.Sprintf("%s:write", r),
   103                          utils.VerbPatch:            fmt.Sprintf("%s:write", r),
   104                          utils.VerbDelete:           fmt.Sprintf("%s:delete", r),
   105                          utils.VerbDeleteCollection: fmt.Sprintf("%s:delete", r),
   106                          utils.VerbGetPermissions:   fmt.Sprintf("%s.permissions:read", r),
   107                          utils.VerbSetPermissions:   fmt.Sprintf("%s.permissions:write", r),
   108                  }
   109          }
   110
   111          return translation{
   112                  resource:          resource,
   113                  attribute:         attribute,
   114                  verbMapping:       defaultMapping(resource),
   115                  folderSupport:     folderSupport,
   116                  skipScopeOnCreate: skipScopeOnCreate,
   117          }
   118  }
