   120  // newDashboardTranslation creates a translation for dashboards and also maps the actions to action sets
   121  func newDashboardTranslation() translation {
   122          dashTranslation := newResourceTranslation("dashboards", "uid", true, false)
   123
   124          actionSetMapping := make(map[string][]string)
   125          for verb, rbacAction := range dashTranslation.verbMapping {
   126                  var dashActionSets []string
   127
   128                  // Dashboard creation is only part of folder action sets, so we handle it separately
   129                  if rbacAction == "dashboards:create" {
   130                          dashActionSets = append(dashActionSets, "folders:edit")
   131                          dashActionSets = append(dashActionSets, "folders:admin")
   132                  }
   133
   134                  if slices.Contains(ossaccesscontrol.DashboardViewActions, rbacAction) {
   135                          dashActionSets = append(dashActionSets, "dashboards:view")
   136                          dashActionSets = append(dashActionSets, "folders:view")
   137                  }
   138                  if slices.Contains(ossaccesscontrol.DashboardEditActions, rbacAction) {
   139                          dashActionSets = append(dashActionSets, "dashboards:edit")
   140                          dashActionSets = append(dashActionSets, "folders:edit")
   141                  }
   142                  if slices.Contains(ossaccesscontrol.DashboardAdminActions, rbacAction) {
   143                          dashActionSets = append(dashActionSets, "dashboards:admin")
   144                          dashActionSets = append(dashActionSets, "folders:admin")
   145                  }
   146                  actionSetMapping[verb] = dashActionSets
   147          }
   148
   149          dashTranslation.actionSetMapping = actionSetMapping
   150          return dashTranslation
   151  }
   152
   153  // newFolderTranslation creates a translation for folders and also maps the actions to action sets
   154  func newFolderTranslation() translation {
   155          folderTranslation := newResourceTranslation("folders", "uid", true, false)
   156
   157          actionSetMapping := make(map[string][]string)
   158          for verb, rbacAction := range folderTranslation.verbMapping {
   159                  var actionSets []string
   160                  // Folder creation has not been added to the FolderEditActions and FolderAdminActions slices (https://github.com/grafana/identity-access-team/issues/794)
   161                  // so we handle it as a special case for now
   162                  if rbacAction == "folders:create" {
   163                          actionSets = append(actionSets, "folders:edit")
   164                          actionSets = append(actionSets, "folders:admin")
   165                  }
   166                  if slices.Contains(ossaccesscontrol.FolderViewActions, rbacAction) {
   167                          actionSets = append(actionSets, "folders:view")
   168                  }
   169                  if slices.Contains(ossaccesscontrol.FolderEditActions, rbacAction) {
   170                          actionSets = append(actionSets, "folders:edit")
   171                  }
   172                  if slices.Contains(ossaccesscontrol.FolderAdminActions, rbacAction) {
   173                          actionSets = append(actionSets, "folders:admin")
   174                  }
   175                  actionSetMapping[verb] = actionSets
   176          }
   177          folderTranslation.actionSetMapping = actionSetMapping
   178          return folderTranslation
   179  }
