   452                                          s.log.Debug("Plugin is attempting to grant access permission, but this permission is already granted by default and will be ignored",
   453                                                  "role", registration.Role.Name, "permission", p.Action, "scope", p.Scope)
   454                                          continue
   455                                  }
   456                                  perm := accesscontrol.Permission{
   457                                          Action: p.Action,
   458                                          Scope:  p.Scope,
   459                                  }
   460
   461                                  perm.Kind, perm.Attribute, perm.Identifier = accesscontrol.SplitScope(perm.Scope)
   462                                  basicRole.Permissions = append(basicRole.Permissions, perm)
   463                          }
   464                  } else {
